package com.oyuki.chat.entity; import com.oyuki.user.entity.User; import jakarta.persistence.*; import lombok.*; import java.time.LocalDateTime; @Entity @Table(name="chat_messages") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class ChatMessage { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="sender_id") private User sender; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="recipient_id") private User recipient; @Column(nullable=false,length=3000) private String message; @Column(nullable=false) @Builder.Default private boolean readFlag=false; private LocalDateTime createdAt; @PrePersist void create(){createdAt=LocalDateTime.now();} }